import { Request, Response, NextFunction } from 'express';
import { ValidationError } from 'zod';
import { ZodError } from 'zod';
import { Logger } from '../utils/logger';

// A structured format for error response
interface ErrorResponse {
  status: number;
  message: string;
  details?: string[];
}

// The generic error handling middleware function
export function errorHandler(err: Error, req: Request, res: Response<ErrorResponse>, next: NextFunction): void {
  // Log the error with requestId if available
  Logger.error('Error handling request', {
    requestId: req.headers['x-request-id'],
    error: err.message,
    stack: err.stack
  });

  let status = 500; // default status
  let response: ErrorResponse = {
    status,
    message: 'Internal Server Error'
  };

  if (err instanceof ZodError) {
    status = 400;
    response = {
      status,
      message: 'Validation Error',
      details: err.errors.map(e => e.message)
    };
  }

  res.status(status).json(response);
}

// A base interface for all DTOs
export interface BaseDTO {
  fromEntity(entity: any): this;
  toEntity(): any;
}

import pino from 'pino';

// Creating a winston logger instance with requestId and timestamp integration
export const Logger = pino({
  level: process.env.NODE_ENV === 'production' ? 'info' : 'debug',
  base: { pid: false },
  timestamp: () => `,"time":"${new Date().toISOString()}"`,
  messageKey: 'message',
});
